def reverseKGroup(head, k):
    c = head; cnt = 0
    while c and cnt < k: c = c.next; cnt += 1
    if cnt == k:
        cur, prev = head, None
        for _ in range(k):
            nxt = cur.next; cur.next = prev; prev = cur; cur = nxt
        head.next = self.reverseKGroup(c, k); return prev
    return head

